  double x, double y, int iterations, double bailout, Vector2 juliaC,
) =>
    _escapeTime(x, -y, iterations, bailout, (zx, zy, cx, cy) {
      final ax = zx.abs();
      final ay = zy.abs();
      // w = (ax, ay), w^3 = w * w^2
      final w2x = ax * ax - ay * ay;
      final w2y = 2.0 * ax * ay;
      return (ax * w2x - ay * w2y + cx, ax * w2y + ay * w2x + cy);
    }, power: 3.0);

